   155→/**
   156→ * Default note values
   157→ */
   158→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   159→  const now = new Date();
   160→  return {
   161→    id: uuidv4(),
   162→    folderId: null,
   163→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   164→    content: '', // Empty Lexical state
   165→    contentText: '',
   166→    tags: [],
   167→    createdAt: now,
   168→    updatedAt: now,
   169→    isPinned: false,
   170→    isArchived: false,
   171→    ...overrides,
   172→  };
   173→};
   174→
   175→/**
   176→ * Sort notes based on sort config
   177→ */
   178→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   179→  const sorted = [...notes];
   180→
   181→  sorted.sort((a, b) => {
   182→    let comparison = 0;
   183→
   184→    switch (config.field) {
   185→      case 'title':
   186→        comparison = a.title.localeCompare(b.title);
   187→        break;
   188→      case 'createdAt':
   189→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   190→        break;
   191→      case 'updatedAt':
   192→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   193→        break;
   194→      case 'manual':
   195→        // Manual sort - preserve order (could add sortOrder field in future)
   196→        comparison = 0;
   197→        break;
   198→    }
   199→
   200→    return config.order === 'asc' ? comparison : -comparison;
   201→  });
   202→
   203→  // Always pin pinned notes to top
   204→  return sorted.sort((a, b) => {
   205→    if (a.isPinned && !b.isPinned) return -1;
   206→    if (!a.isPinned && b.isPinned) return 1;
   207→    return 0;
   208→  });
   209→};
   210→
   211→/**
   212→ * Filter notes based on filter type
   213→ */
   214→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   215→  switch (filter) {
   216→    case 'favorites':
   217→      return notes.filter((note) => note.isFavorite);
   218→    case 'pinned':
   219→      return notes.filter((note) => note.isPinned);
   220→    case 'archived':
   221→      return notes.filter((note) => note.isArchived);
   222→    case 'unarchived':
   223→      return notes.filter((note) => !note.isArchived);
   224→    case 'all':
   225→    default:
   226→      return notes;
   227→  }
   228→};
