   830→        return Object.values(get().notes).filter(
   831→          (note) => note.folderId === folderId
   832→        );
   833→      },
   834→
   835→      exportNotes: () => {
   836→        return Object.values(get().notes);
   837→      },
   838→
   839→      importNotes: (notes, merge) => {
   840→        if (!merge) {
   841→          // Replace all notes
   842→          set({
   843→            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   844→            activeNoteId: null,
   845→          });
   846→          log.info('Imported notes', { count: notes.length, mode: 'replace' });
   847→        } else {
   848→          // Merge with existing notes
   849→          set((state) => {
   850→            const updatedNotes = { ...state.notes };
   851→            notes.forEach((note) => {
   852→              updatedNotes[note.id] = note;
   853→            });
   854→            return { notes: updatedNotes };
   855→          });
   856→          log.info('Imported notes', { count: notes.length, mode: 'merge' });
   857→        }
   858→      },
   859→
   860→      clearAllNotes: () => {
   861→        set({ notes: {}, activeNoteId: null });
   862→        log.info('All notes cleared');
   863→      },
   864→
   865→      // ==================== BACKLINKS (Phase 4) ====================
   866→
   867→      getBacklinks: (noteId: string) => {
   868→        const state = get();
   869→        const note = state.notes[noteId];
   870→        if (!note) return [];
   871→
   872→        return getBacklinksUtil(noteId, note.title, state.notes);
   873→      },
   874→
   875→      updateLinkedNotes: (noteId: string, content: string) => {
   876→        const state = get();
   877→        const linkTitles = extractWikiLinks(content);
   878→        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);
   879→
   880→        set((currentState) => {
   881→          const note = currentState.notes[noteId];
   882→          if (!note) return currentState;
   883→
   884→          return {
   885→            notes: {
   886→              ...currentState.notes,
   887→              [noteId]: {
   888→                ...note,
   889→                linkedNotes: linkedNoteIds,
   890→              },
   891→            },
   892→          };
   893→        });
   894→      },
   895→
   896→      // ==================== TEMPLATES (Phase 4) ====================
   897→
   898→      getNoteTemplates: () => {
   899→        return DEFAULT_NOTE_TEMPLATES;
   900→      },
   901→
   902→      createNoteFromTemplate: (templateId: string) => {
   903→        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
   904→        if (!template) return null;
   905→
   906→        const newNote = createDefaultNote({
   907→          title: template.name,
   908→          contentText: template.description,
   909→          tags: template.defaultTags || [],
   910→          icon: template.icon,
   911→        });
   912→
   913→        set((state) => ({
   914→          notes: {
   915→            ...state.notes,
   916→            [newNote.id]: newNote,
   917→          },
   918→          activeNoteId: newNote.id,
   919→        }));
   920→
   921→        log.debug('Created note from template', { template: template.name });
   922→        return newNote;
   923→      },
   924→
   925→      // ==================== DAILY NOTES ====================
   926→
   927→      getDailyNote: (date: Date) => {
   928→        const state = get();
   929→        const settings = useSettingsStore.getState().dailyNotes;
   930→        return getDailyNoteUtil(date, state.notes, settings);
   931→      },
   932→
   933→      createDailyNote: (date: Date) => {
   934→        const settings = useSettingsStore.getState().dailyNotes;
   935→        const newNote = createDailyNoteUtil(date, settings);
   936→
   937→        set((state) => ({
   938→          notes: {
   939→            ...state.notes,
   940→            [newNote.id]: newNote,
   941→          },
   942→          activeNoteId: newNote.id,
   943→        }));
   944→
   945→        log.info('Created daily note', { date: newNote.title, id: newNote.id });
   946→        return newNote;
   947→      },
   948→
   949→      getOrCreateDailyNote: (date: Date) => {
   950→        const state = get();
   951→        const settings = useSettingsStore.getState().dailyNotes;
   952→
   953→        // Try to find existing note
   954→        const existingNote = getDailyNoteUtil(date, state.notes, settings);
   955→        if (existingNote) {
   956→          // Set as active note
   957→          set({ activeNoteId: existingNote.id });
   958→          log.debug('Found existing daily note', { date: existingNote.title });
   959→          return existingNote;
   960→        }
   961→
   962→        // Create new note
   963→        const newNote = createDailyNoteUtil(date, settings);
   964→        set((currentState) => ({
   965→          notes: {
   966→            ...currentState.notes,
   967→            [newNote.id]: newNote,
   968→          },
   969→          activeNoteId: newNote.id,
   970→        }));
   971→
   972→        log.info('Auto-created daily note', { date: newNote.title, id: newNote.id });
   973→        return newNote;
   974→      },
   975→    }),
   976→    {
   977→      name: 'notes', // IndexedDB key
   978→      storage: createJSONStorage(() => createSyncedStorage()),
   979→      partialize: (state) => ({
   980→        // Only persist notes, not UI state
   981→        notes: state.notes,
   982→      }),
   983→      // Handle date serialization
   984→      onRehydrateStorage: () => (state) => {
   985→        log.debug('Notes store rehydrating');
   986→        if (state) {
   987→          try {
   988→            // Ensure notes object exists and is valid
   989→            if (state.notes && typeof state.notes === 'object') {
   990→              // Convert date strings back to Date objects
   991→              Object.values(state.notes).forEach((note) => {
   992→                if (typeof note.createdAt === 'string') {
   993→                  note.createdAt = new Date(note.createdAt);
   994→                }
   995→                if (typeof note.updatedAt === 'string') {
   996→                  note.updatedAt = new Date(note.updatedAt);
   997→                }
   998→              });
   999→            } else {
  1000→              log.warn('Corrupted notes data detected, resetting to empty');
  1001→              state.notes = {};
  1002→            }
  1003→          } catch (err) {
  1004→            log.error('Error during notes store rehydration', { error: err });
  1005→            // Reset to safe defaults
  1006→            state.notes = {};
  1007→            state.activeNoteId = null;
  1008→          }
  1009→        }
  1010→        log.info('Notes store rehydrated');
  1011→      },
  1012→    }
  1013→  )
  1014→);
  1015→
  1016→/**
  1017→ * Selector hooks for optimized re-renders
  1018→ */
  1019→export const useActiveNote = () =>
  1020→  useNotesStore((state) => {
  1021→    const activeId = state.activeNoteId;
  1022→    return activeId ? state.notes[activeId] : null;
  1023→  });
  1024→
